def is_valid_url(url):
    if not url or len(url) > MAX_URL_LENGTH:
        return False
    parsed = urlparse(url)
    if parsed.scheme not in ("http", "https"):
        return False
    if not parsed.netloc:
        return False
    hostname = parsed.hostname or ""
    if not ALLOW_PRIVATE_IPS:
        if hostname in ("localhost",):
            return False
        private_patterns = (
            r"^10\.",
            r"^127\.",
            r"^169\.254\.",
            r"^172\.(1[6-9]|2\d|3[0-1])\.",
            r"^192\.168\.",
            r"^\[?::1\]?$",
            r"^fc00:",
            r"^fd00:",
        )
        for pat in private_patterns:
            if re.match(pat, hostname, re.IGNORECASE):
                return False
    return True


def s3_key_for_url(url, ext="png"):
    digest = hashlib.sha256(url.encode("utf-8")).hexdigest()
    return f"{S3_PREFIX}/{digest[:2]}/{digest}.{ext}"


def s3_thumb_key_for_url(url, ext="jpg"):
    digest = hashlib.sha256((url + "|thumb").encode("utf-8")).hexdigest()
    return f"{S3_PREFIX}/thumb/{digest[:2]}/{digest}.{ext}"


def s3_put_bytes(key, data, content_type, cache_control=CACHE_CONTROL):
    if not s3:
        raise RuntimeError("S3 bucket not configured")
    s3.put_object(
        Bucket=S3_BUCKET,
        Key=key,
        Body=data,
        ContentType=content_type,
        CacheControl=cache_control,
        ACL="private",
    )


def s3_get_bytes(key):
    if not s3:
        return None
    try:
        obj = s3.get_object(Bucket=S3_BUCKET, Key=key)
        return obj["Body"].read(), obj.get("ContentType", "application/octet-stream")
    except ClientError as e:
        code = e.response.get("Error", {}).get("Code")
        if code in ("NoSuchKey", "404", "NotFound"):
            return None
        raise


def s3_exists(key):
    if not s3:
        return False
    try:
        s3.head_object(Bucket=S3_BUCKET, Key=key)
        return True
    except ClientError as e:
        code = e.response.get("Error", {}).get("Code")
        if code in ("404", "NoSuchKey", "NotFound"):
            return False
        raise


